import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty policy ---
  it("quote with empty item list returns premium 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums for single main items (with 5 G fee, newcomer 10% first-insurance) ---
  // Note: a single-item quote for a newcomer with 0 years is the minimal sensible scenario.
  // To keep the simplest tests truly simple, we test the base-premium examples through
  // long-standing-customer follow-up scenarios where only the base + fee apply.
  // We test base premiums first via the spec examples about building blocks (which are
  // explicitly described as "base premiums"). So we start there.

  // --- Building block of 3 alike components (base premium examples from spec) ---
  it("2 runes have base premium 50 G (2 x 25 G, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it("3 runes have base premium 60 G (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("4 runes have base premium 100 G (no block — block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("7 runes have base premium 175 G (no block possible across 7)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 180 }] });
  });

  // --- "Alike" components clarification (❓ same type, not same family) ---
  it("2 runes + 1 moonstone have base premium 75 G (no block — different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 80 }] });
  });
  it("3 runes + 3 moonstones have base premium 120 G (two separate blocks of 3 same type)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 125 }] });
  });

  // --- Modifier thresholds ---
  it("customer with exactly 2 years receives loyalty discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("sword with exactly enchantment 5 gets high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 does NOT get high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with enchantment 5 gets both curse and high-enchantment surcharges", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // --- Rounding rules ---
  it("premium calculation yielding 197.5 G rounds UP to 198 G (MHPCO favor)", () => {
    // customer 2y with 2nd quote: cursed sword (ench 5) + 2 runes
    // base = 100 + 50 = 150
    // cursed = 50, high-ench = 30, first-insurance = 15 (10% of policy base 150)
    // loyalty = 30 (20% of 150), follow-up = 22.5 (15% of 150)
    // total = 150 + 50 + 30 + 15 - 30 - 22.5 + 5 = 197.5 -> rounds UP to 198
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0 }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect((result as { results: Array<{ premium: number }> }).results[1]).toEqual({ premium: 198 });
  });
  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (MHPCO favor)");
  it.todo("intermediate amounts are kept as fractions; only the final premium/payout is rounded");

  // --- Modifier scope on multi-item policies (❓ item-specific vs policy-wide) ---
  it.todo("policy with cursed sword (100 G base) + plain amulet (60 G base) has policy base 160 G; curse adds 50 G (50% of sword base, not policy total) → 210 G before further modifiers and fee");
  it.todo("item-specific modifiers (cursed, high enchantment) apply to the affected item's base premium");
  it.todo("policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium");
  it.todo("processing fee is added at the very end after all other modifiers");

  // --- Integration example 1: Newcomer with cursed sword ---
  it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance = 160 + 5 fee)");

  // --- Integration example 2: Long-standing customer's second contract ---
  it.todo("long-standing customer (3 years, 2nd quote) with cursed sword (steel, ench 7) → premium 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-insurance - 15 follow-up = 155 + 5 fee)");
  it.todo("first-insurance surcharge applies to every item in every quote, regardless of customer history (❓ clarification)");

  // --- Claim processing: standard reimbursement (no special clauses) ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full minus 100 deductible; no special clause)");

  // --- Claim processing: deductible per damage event ---
  it.todo("dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (100 deductible per item)");

  // --- Enchantment threshold vs. dragon material ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause: 50%, then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material, then deductible: 500 - 100)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause: full, then deductible: 800 - 100)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause: 50%, then deductible: 500 - 100)");

  // --- Multiple items of the same type (❓ two swords) ---
  it.todo("policy covers two swords → insurance sum 2000 G (= 2 x 1000)");
  it.todo("dragon attack damages both swords; each damages entry treated as separate damage with own deductible");
  it.todo("damages array contains more entries of a type than the policy covers → whole claim rejected (non-zero exit)");

  // --- Edge cases ---
  it.todo("quote includes item with unknown type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
  it.todo("claim references damage entry for an item not part of the policy (e.g. amulet damaged when only sword insured) → non-zero exit, error on stderr");
  it.todo("claim references damage entry with unknown item type → non-zero exit, error on stderr");
  it.todo("claim contains a damage entry with amount -200 → non-zero exit, error on stderr");

  // --- CLI integration (reads JSON from stdin, writes results to stdout) ---
  it.todo("CLI scenario with a quote step writes {results: [{premium: N}]} to stdout");
